import{_ as t,o as s,c as r,ae as a}from"./chunks/framework.D6sYw4vw.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"awesome-carbon-neutrality/RenewableEnergy/sam-ssc.md","filePath":"awesome-carbon-neutrality/RenewableEnergy/sam-ssc.md","lastUpdated":1773144464000}'),o={name:"awesome-carbon-neutrality/RenewableEnergy/sam-ssc.md"};function l(n,e,c,i,u,d){return s(),r("div",null,[...e[0]||(e[0]=[a('<p>@def title = &quot;System Advisor Model(SAM)及ssc&quot; @def hascode = true @def date = Date(2021, 11, 19) @def rss = &quot;System Advisor Model(SAM)及ssc&quot; @def tags = [&quot;SAM&quot;, &quot;solar energy&quot;, &quot;ssc&quot;]</p><ul><li><a href="https://github.com/NREL/SAM" target="_blank" rel="noreferrer">System Advisor Model</a></li></ul><p>由美国能源部委托美国国家可再生能源实验室（NREL）开发的可再生能源项目评估模型软件。</p><p>SAM软件可针对光伏、光热、风力、地热、生物质等几种可再生能源的发电成本及系统发电特性进行计算。通过导入所需测算地点的天气参数、系统类型、系统规模、系统盈利模式、及系统投资等参数既可得到系统均化发电成本，从而完成对可再生能源项目收益的初步测算。</p><p>SAM软件主要包含两个仿真模型，即性能模型和融资模型。可再生能源混合能源系统项目设计人员可以通过SAM模拟计算进行项目技术性分析及经济性分析，对于项目前期开发有一定帮助。</p><ul><li><a href="https://github.com/NREL/ssc" target="_blank" rel="noreferrer">SSC</a></li></ul><p><a href="https://github.com/NREL/SAM" target="_blank" rel="noreferrer">SAM</a>模型的性能模型和融资模型计算内核源代码。</p><p>在<a href="https://github.com/NREL/SAM" target="_blank" rel="noreferrer">SAM的github版本库</a>中提供了ssc及sam的详细编译安装过程(<a href="https://github.com/NREL/SAM/wiki" target="_blank" rel="noreferrer">https://github.com/NREL/SAM/wiki</a>)。ssc编译之后以动态链接库（Windows平台是ssc.dll，Linux平台是ssc.so, Mac平台是ssc.dylib）的形式支撑sam，sam是基于wxWidgets编写的GUI壳。</p>',8)])])}const _=t(o,[["render",l]]);export{m as __pageData,_ as default};
